SELECT ?team ?seasonsWon
WHERE {
  ?team wdt:P31 wd:Q207694 ;
        wdt:P460 wd:Q11862752 ;
        wdt:P2522 wd:Q18156668 .
  {
    SELECT ?team (COUNT(DISTINCT ?season) AS ?seasonsWon)
    WHERE {
      ?team wdt:P31 wd:Q207694 ;
            wdt:P460 wd:Q11862752 ;
            wdt:P2522 wd:Q18156668 ;
            wdt:P5138 ?season .
    }
    GROUP BY ?team
  }
  FILTER(?seasonsWon >= 2)
}

