SELECT ?population ?time ?previousPopulation WHERE {
  wd:Q683 wd:P1082 ?population .
  wd:Q683 wdt:P580 ?time .
  FILTER (?time > "2006-01-01"^^xsd:date) .
  {
    SELECT ?time ?previousPopulation WHERE {
      wd:Q683 wdt:P1082 ?previousPopulation .
      wd:Q683 wdt:P580 ?previousTime .
      FILTER (?previousTime < ?time) .
      FILTER (?previousTime > "2006-01-01"^^xsd:date) .
    }
    ORDER BY DESC(?previousTime)
    LIMIT 1
  }
  FILTER (?population > ?previousPopulation)
}

