SELECT ?year (COUNT(?award) AS ?count)
WHERE {
  {
    wd:Q169452 wdt:P166 ?award .
    ?award wdt:P1411 wd:Q674359 .
    ?award wdt:P6262 ?year .
    BIND(?year AS ?year1)
  }
  UNION
  {
    wd:Q25369 wdt:P166 ?award .
    ?award wdt:P1411 wd:Q674359 .
    ?award wdt:P6262 ?year .
    BIND(?year AS ?year2)
  }
  FILTER (?year1 = ?year2)
}
GROUP BY ?year

